#include <iostream>
using namespace std;
int main()
{
    int a;
    scanf("%d",&a);
    long b[a],s=0;
    for(int i=0;i<a;i++)
        {
            scanf("%ld",&b[i]);
        }
    for(int i=0;i<a-1;i++)
        {
            int min=i;
            for(int j=i+1;j<a;j++)
                {
                    if(b[min]>b[j])
                    {
                        min=j;
                    }
                }
            s=b[min];
            b[min]=b[i];
            b[i]=s;
        }
    for(int i=0;i<a;i++)
        {
            printf("%ld ",b[i]);
        }
}
